      'ai-faceless-channel-pipeline': 'aifacelesschannelpipeline',
      'bilingual-ai-flashcards-early-childhood-education': 'bilingual-ai-flashcards-early-childhood-education',
      'ugcVideoTranslationScalingTiktoksShortsGlobalMarkets': 'ugcVideoTranslationScalingTiktoksShortsGlobalMarkets',
