            'brazil-argentina-soccer-poster-prompts': 'brazilArgentinaSoccerPosterPrompts',
            'portugal-soccer-poster-prompts': 'portugalSoccerPosterPrompts',
            'ai-1v1-soccer-rivalry-prompts': 'ai1v1SoccerRivalryPrompts',
            'france-soccer-poster-prompts': 'franceSoccerPosterPrompts',
